const { CosmosClient } = require("@azure/cosmos");
const { app, timerTrigger } = require("@azure/functions");

const cosmosClient = new CosmosClient(process.env.COSMOS_DB_CONNECTION_STRING);
const database = cosmosClient.database(process.env.COSMOS_DB_NAME);
const container = database.container(process.env.COSMOS_CONTAINER_NAME);

app.timerTrigger("batchProcessor", {
    schedule: "0 */5 * * * *",
    handler: async function (context, myTimer) {
        context.log('Batch processor function started at:', new Date().toISOString());
        
        try {
            // Set timeout to maximum allowed (10 minutes for Consumption plan)
            const timeout = 600000; // 10 minutes in milliseconds
            
            // Process data in batches to prevent timeouts
            let continuationToken = null;
            let processedCount = 0;
            
            do {
                // Query with continuation token for large datasets
                const query = {
                    query: "SELECT * FROM c WHERE c.processed = false",
                    parameters: [],
                    continuation: continuationToken
                };
                
                const { resources, continuation } = await container.items.query(query, {
                    maxItemCount: 100,
                    enableCrossPartitionQuery: true
                });
                
                continuationToken = continuation;
                
                if (resources.length > 0) {
                    // Process batch
                    await processBatch(resources, context);
                    processedCount += resources.length;
                    
                    // Update processed status in Cosmos DB
                    await updateProcessedStatus(resources);
                }
                
                // Check if we're approaching timeout
                if (Date.now() - myTimer.scheduleStatus.last > timeout - 30000) {
                    context.log(`Approaching timeout, processing will continue in next execution`);
                    break;
                }
                
            } while (continuationToken);
            
            context.log(`Batch processing completed. Processed ${processedCount} items.`);
            
        } catch (error) {
            context.log.error('Error in batch processing:', error);
            throw error;
        }
    }
});

async function processBatch(items, context) {
    // Process each item in the batch
    for (const item of items) {
        try {
            // Your processing logic here
            await processItem(item, context);
            
            // Add small delay to prevent overwhelming the system
            await new Promise(resolve => setTimeout(resolve, 10));
        } catch (error) {
            context.log.error(`Error processing item ${item.id}:`, error);
            // Continue with other items
        }
    }
}

async function processItem(item, context) {
    // Implement your specific data processing logic here
    // Example: transform, validate, enrich, etc.
    
    // Simulate processing time
    await new Promise(resolve => setTimeout(resolve, 50));
    
    // Update item with processed data
    item.processed = true;
    item.processedAt = new Date().toISOString();
}

async function updateProcessedStatus(items) {
    // Update processed status in Cosmos DB
    const promises = items.map(async (item) => {
        try {
            await container.item(item.id).replace(item);
        } catch (error) {
            console.error(`Failed to update item ${item.id}:`, error);
        }
    });
    
    await Promise.allSettled(promises);
}

// Security measures
const crypto = require('crypto');
const secret = process.env.SECURITY_SECRET;

function validateRequest(request) {
    const expectedSignature = crypto
        .createHmac('sha256', secret)
        .update(JSON.stringify(request))
        .digest('hex');
    
    return request.signature === expectedSignature;
}

